'use strict';

// Categories 101-200 — structured from user specifications.
function hslToHex(h, s, l) {
  s /= 100;
  l /= 100;
  const c = (1 - Math.abs(2 * l - 1)) * s;
  const x = c * (1 - Math.abs(((h / 60) % 2) - 1));
  const m = l - c / 2;
  let rgb;
  if (h < 60) rgb = [c, x, 0];
  else if (h < 120) rgb = [x, c, 0];
  else if (h < 180) rgb = [0, c, x];
  else if (h < 240) rgb = [0, x, c];
  else if (h < 300) rgb = [x, 0, c];
  else rgb = [c, 0, x];
  return `#${rgb.map((v) => Math.round((v + m) * 255).toString(16).padStart(2, '0')).join('')}`;
}

function makeColors(num, dark) {
  const hue = (num * 47) % 360;
  return dark
    ? { bg: hslToHex(hue, 30, 10), card: hslToHex(hue, 25, 17), accent: hslToHex((hue + 28) % 360, 78, 62), text: '#f7f8fa' }
    : { bg: hslToHex(hue, 42, 96), card: hslToHex(hue, 34, 90), accent: hslToHex(hue, 58, 38), text: hslToHex(hue, 28, 18) };
}

